// // This module implements a 2-to-1 multiplexer where Y equals A when SEL is 1, and B when SEL is 0.
module mux_2to1 (
    input A,
    input B,
    input SEL,
    output Y
);

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    // Output assignment
    assign Y = SEL ? B : A;

endmodule
